func Translate(text string, defaultTranslation ...rune) string {
	dtr := rune(0x7f)
	if len(defaultTranslation) == 1 {
		dtr = defaultTranslation[0]
	}

	out := ""
	for _, rune := range text {
		safeRune, ok := translations[rune]
		if ok {
			out += safeRune
		} else {
			out += string(dtr)
		}
	}

	strings.ReplaceAll(out, string(rune(0x7f)), "")

	return out
}
